const countries = ($json.countries || []).map(c => String(c));
const officialJobSources = {
 'United States': ['https://www.careeronestop.org/','https://www.bls.gov/ooh/'],
 'United Kingdom': ['https://findajob.dwp.gov.uk/','https://www.gov.uk/browse/working/finding-job'],
 'Canada': ['https://www.jobbank.gc.ca/home'],
 'Australia': ['https://www.workforceaustralia.gov.au/individuals/jobs/'],
 'Germany': ['https://www.make-it-in-germany.com/en/working-in-germany/job-listings'],
 'France': ['https://www.francetravail.fr/accueil/'],
 'Netherlands': ['https://www.werk.nl/werkzoekenden/'],
 'Ireland': ['https://www.jobsireland.ie/'],
 'New Zealand': ['https://www.jobs.govt.nz/'],
 'Singapore': ['https://www.mycareersfuture.gov.sg/'],
 'Japan': ['https://www.hellowork.mhlw.go.jp/'],
 'Sweden': ['https://arbetsformedlingen.se/'],
 'Norway': ['https://www.nav.no/en/home/work-and-stay-in-norway/work-in-norway'],
 'Denmark': ['https://jobnet.dk/'],
 'Finland': ['https://tyomarkkinatori.fi/en'],
 'UAE': ['https://www.mohre.gov.ae/en/services.aspx']
};
const adzunaCountryCode = { 'United States':'us','United Kingdom':'gb','Canada':'ca','Australia':'au','Germany':'de','France':'fr','Netherlands':'nl','Singapore':'sg' };
const out = [];
for (const country of countries){
  const sources = officialJobSources[country] || [];
  for (const url of sources){ out.push({json:{country, url, sourceType:'official_jobs_site'}}); }
  if (adzunaCountryCode[country]) { out.push({json:{country, url:`https://api.adzuna.com/v1/api/jobs/${adzunaCountryCode[country]}/search/1`, sourceType:'adzuna_api'}}); }
}
return out;

const src = $item(0).$node['Split In Batches'].json;
const statusCode = Number($json.statusCode || 0);
const ok = statusCode >= 200 && statusCode < 500;
return [{json:{country: src.country, url: src.url, sourceType: src.sourceType, statusCode, ok}}];
